import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input, which contains a script tag
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by escaping special characters before outputting it to an HTML response
        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println("<html><body>");
            out.println("<h1>Welcome</h1>");
            out.println("<p>User Input: " + StringEscapeUtils.escapeHtml4(userInput) + "</p>");
            out.println("</body></html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

